class CourseStudent { private String studentName; private String courseName; private double courseFee; private double discountPercent; public void setStudentName(String s){studentName=s;} public void setCourseName(String c){courseName=c;} public void setCourseFee(double f){courseFee=f;} public void setDiscountPercent(double d){discountPercent=d;} public double getFinalFee(){ return courseFee-(courseFee*discountPercent/100);} }